CREATE OR REPLACE FUNCTION is_admin()
RETURNS BOOLEAN AS $$
DECLARE
  v_is_admin BOOLEAN;
  v_user_id UUID := auth.uid()::uuid;
BEGIN
  SELECT is_admin INTO v_is_admin FROM public.users WHERE id = v_user_id;
  RETURN COALESCE(v_is_admin, FALSE);
END;
$$ LANGUAGE plpgsql
SECURITY DEFINER;
GRANT EXECUTE ON FUNCTION is_admin() TO authenticated;
CREATE OR REPLACE FUNCTION has_admin_access()
RETURNS BOOLEAN AS $$
DECLARE
  v_user_id UUID := auth.uid()::uuid;
BEGIN
  IF v_user_id IS NULL THEN
    RETURN FALSE;
  END IF;
  IF is_admin() THEN
    RETURN TRUE;
  END IF;
  RETURN EXISTS (
    SELECT 1
    FROM public.event_admins ea
    WHERE ea.user_id = v_user_id
  );
END;
$$ LANGUAGE plpgsql
SECURITY DEFINER;
GRANT EXECUTE ON FUNCTION has_admin_access() TO authenticated;
CREATE OR REPLACE FUNCTION get_email_by_username(p_username TEXT)
RETURNS TEXT AS $$
DECLARE v_email TEXT;
BEGIN
  SELECT au.email
  INTO v_email
  FROM auth.users au
  JOIN public.users u ON u.id = au.id
  WHERE u.username = p_username;
  RETURN v_email;
END;
$$ LANGUAGE plpgsql
SECURITY DEFINER;
GRANT EXECUTE ON FUNCTION get_email_by_username(text) TO anon, authenticated;
CREATE OR REPLACE FUNCTION get_username_by_email(p_email TEXT)
RETURNS TEXT AS $$
DECLARE v_username TEXT;
BEGIN
  SELECT u.username
  INTO v_username
  FROM public.users u
  JOIN auth.users au ON au.id = u.id
  WHERE LOWER(au.email) = LOWER(p_email);
  RETURN v_username;
END;
$$ LANGUAGE plpgsql
SECURITY DEFINER;
