CREATE OR REPLACE FUNCTION cleanup_orphaned_users_and_solves()
RETURNS void AS $$
BEGIN
  DELETE FROM public.solves
  WHERE user_id NOT IN (SELECT id FROM auth.users);
  DELETE FROM public.users
  WHERE id NOT IN (SELECT id FROM auth.users);
END;
$$ LANGUAGE plpgsql
SECURITY DEFINER;
