  v_count INTEGER;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only admin can update challenges event';
  END IF;
  UPDATE public.challenges
  SET event_id = p_event_id,
      updated_at = now()
  WHERE id = ANY(p_challenge_ids);
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$ LANGUAGE plpgsql
